const ASSETS = {"/modules/wloc.conf":{"contentType":"text/plain; charset=utf-8","base64":""},"/modules/wloc.lpx":{"contentType":"text/plain; charset=utf-8","base64":""},"/modules/wloc.module":{"contentType":"text/plain; charset=utf-8","base64":""},"/modules/wloc.sgmodule":{"contentType":"text/plain; charset=utf-8","base64":""},"/modules/wloc.stoverride":{"contentType":"text/yaml; charset=utf-8","base64":""},"/dist/wloc-settings.js":{"contentType":"application/javascript; charset=utf-8","base64":""},"/dist/wloc.js":{"contentType":"application/javascript; charset=utf-8","base64":""},"/wloc.jpg":{"contentType":"image/jpeg","base64":""}};

export function getAsset(path) {
  const asset = ASSETS[path];
  if (!asset) return null;
  const binary = atob(asset.base64);
  const body = Uint8Array.from(binary, (char) => char.charCodeAt(0));
  return { contentType: asset.contentType, body };
}
